   953→// AI interviewer conducts a conversational interview turn
   954→async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
   955→  // Send last 12 turns for better context on follow-ups
   956→  const recentConvo = conversation.slice(-12);
   957→  const convoText = recentConvo.map(turn => {
   958→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
   959→    return `CANDIDATE: ${turn.text}`;
   960→  }).join('\n\n');
   961→
   962→  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
   963→  const followUpCount = conversation.filter(t => t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')).length;
   964→  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
   965→  const nextPlannedQuestion = remainingQuestions.length > 0
   966→    ? remainingQuestions[0].question_text
   967→    : null;
   968→
   969→  // Count consecutive follow-ups on the current topic
   970→  let consecutiveFollowUps = 0;
   971→  for (let i = conversation.length - 1; i >= 0; i--) {
   972→    const t = conversation[i];
   973→    if (t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')) {
   974→      consecutiveFollowUps++;
   975→    } else if (t.role === 'interviewer' && t.action === 'transition') {
   976→      break;
   977→    } else if (t.role === 'candidate') {
   978→      continue; // skip candidate turns when counting
   979→    }
   980→  }
   981→
   982→  const prompt = `You are conducting a mock interview for a "${targetRole}" position. You have ${remainingQuestions.length} planned questions remaining.
   983→
   984→CONVERSATION SO FAR:
   985→${convoText}
   986→
   987→${nextPlannedQuestion ? `NEXT PLANNED QUESTION (use when ready to move on): "${nextPlannedQuestion}"` : 'All planned questions covered.'}
   988→
   989→FOLLOW-UP COUNT on current topic: ${consecutiveFollowUps}
   990→
   991→YOUR TASK: Act like a real interviewer. After the candidate answers:
   992→
   993→1. **FOLLOW UP** if the answer is:
   994→   - Vague or surface-level ("I worked on a project" → ask WHAT project, what was the challenge)
   995→   - Missing specifics (no metrics, no concrete examples, no details about their role)
   996→   - Interesting but unexplored (they mentioned something worth digging into)
   997→   - Missing the "so what" (they described what happened but not the impact/result)
   998→   You can ask MULTIPLE follow-ups on the same topic. Keep probing until you have real depth.
   999→
  1000→2. **TRANSITION** to the next planned question when:
  1001→   - The candidate gave a thorough, specific answer with concrete examples
  1002→   - You've already asked 2-3 follow-ups and have sufficient depth
  1003→   - The candidate clearly has nothing more to add on this topic
  1004→
  1005→3. **WRAP UP** when: ${candidateTurnCount >= 6 ? 'You feel you have enough data (6+ exchanges completed)' : 'NOT YET — keep interviewing, only ' + candidateTurnCount + ' exchanges so far'}
  1006→
  1007→React to their answer specifically (1-2 sentences — reference something concrete they said, NOT generic filler like "Thank you for that response" or "That's helpful"). Show you actually listened. Example good reactions: "That 40% improvement in pipeline throughput is impressive — how did you measure that?" or "Interesting that you chose to refactor first rather than ship the feature." Example bad reactions: "Thank you for sharing that." or "That's great, thanks."
  1008→
  1009→Return JSON: {"reaction":"1-2 sentences referencing SPECIFIC details from their answer","action":"follow_up|challenge|transition|wrap_up","question":"your next question","score_hint":1-10,"notes":"brief note on answer quality"}`;
  1010→
  1011→  const result = await chat(prompt, {
  1012→    system: `You are Alex, an experienced ${targetRole} interviewer. You conduct interviews like a real person — curious, attentive, and thorough. You don't just read from a script. When a candidate gives a vague answer, you probe deeper. When they mention something interesting, you explore it. You ask follow-up questions naturally, like "Tell me more about that" or "What specifically was your role in that?" or "How did you measure success?" You only move to the next planned question when you're genuinely satisfied with the depth of their answer. Always return valid JSON only.`,
  1013→    maxTokens: 1024,
  1014→    subscriptionId: options.subscriptionId,
  1015→    module: 'mock_interview', feature: 'interview_turn'
  1016→  });
  1017→
  1018→  const parsed = safeParseJSON(result);
  1019→  if (parsed) return parsed;
  1020→  throw new Error('Failed to generate interview turn — could not parse LLM response');
  1021→}
